### Реализация системы сборки (`build-system.js`)

Этот скрипт выполняет все этапы: очистку, генерацию, компиляцию и копирование.

```javascript
const fs = require('fs');
const path = require('path');

// Конфигурация путей
const CONFIG = {
    src: './src',
    dist: './public', // Публичный каталог
    subdirs: ['css', 'js', 'assets', 'generated']
};

// Цвета для логов
const colors = {
    reset: '\x1b[0m',
    green: '\x1b[32m',
    yellow: '\x1b[33m',
    blue: '\x1b[34m',
    red: '\x1b[31m'
};

const log = (msg, color = 'reset') => console.log(`${colors[color]}[BUILD]${colors.reset} ${msg}`);

/**
 * 1. Очистка и создание структуры публичного каталога
 */
function setupPublicDirectory() {
    log('Очистка и создание структуры публичного каталога...', 'blue');

    // Удаляем старый dist, если существует
    if (fs.existsSync(CONFIG.dist)) {
        fs.rmSync(CONFIG.dist, { recursive: true, force: true });
    }

    // Создаем корень и подкаталоги
    fs.mkdirSync(CONFIG.dist, { recursive: true });
    CONFIG.subdirs.forEach(dir => {
        const fullPath = path.join(CONFIG.dist, dir);
        fs.mkdirSync(fullPath, { recursive: true });
        log(`Создан каталог: ${fullPath}`, 'green');
    });
}

/**
 * 2. Генерация файлов парсеров
 * Симулирует чтение спецификации и генерацию JS-кода парсера
 */
function generateParserFiles() {
    log('Генерация файлов парсеров...', 'yellow');

    const specPath = path.join(CONFIG.src, 'specs', 'parser-spec.json');
    const outputDir = path.join(CONFIG.dist, 'generated');

    if (!fs.existsSync(specPath)) {
        log('Спецификация парсера не найдена, создаем заглушку.', 'red');
        // Создаем демо-спецификацию, если её нет
        fs.writeFileSync(specPath, JSON.stringify({ name: "DemoParser", rules: ["A", "B"] }, null, 2));
    }

    const specData = JSON.parse(fs.readFileSync(specPath, 'utf-8'));

    // Генерируем код парсера на основе спецификации
    const parserCode = `
// Автогенерируемый файл парсера
// Источник: ${specPath}
// Версия: 1.0.0

class ${specData.name} {
    constructor() {
        this.rules = ${JSON.stringify(specData.rules)};
        console.log("Парсер ${specData.name} инициализирован");
    }

    parse(input) {
        // Логика парсинга...
        return input.split('').reverse().join('');
    }
}

module.exports = ${specData.name};
`;

    const outputPath = path.join(outputDir, 'parser.js');
    fs.writeFileSync(outputPath, parserCode);
    log(`Сгенерирован парсер: ${outputPath}`, 'green');
}

/**
 * 3. Обработка шаблонов
 * Заменяет плейсхолдеры {{VARIABLE}} на реальные значения
 */
function processTemplates() {
    log('Обработка шаблонов...', 'yellow');

    const templatePath = path.join(CONFIG.src, 'templates', 'index.html.tpl');
    const outputPath = path.join(CONFIG.dist, 'index.html');

    // Создаем демо-шаблон, если его нет
    if (!fs.existsSync(templatePath)) {
        const demoTemplate = `
<!DOCTYPE html>
<html lang="ru">
<head>
    <meta charset="UTF-8">
    <title>{{TITLE}}</title>
    <link rel="stylesheet" href="css/main.css">
</head>
<body>
    <h1>{{HEADER}}</h1>
    <p>Версия сборки: {{BUILD_VERSION}}</p>
    <script src="generated/parser.js"></script>
</body>
</html>`;
        fs.mkdirSync(path.dirname(templatePath), { recursive: true });
        fs.writeFileSync(templatePath, demoTemplate);
    }

    let content = fs.readFileSync(templatePath, 'utf-8');

    // Данные для подстановки
    const replacements = {
        '{{TITLE}}': 'Мой Веб-Проект',
        '{{HEADER}}': 'Добро пожаловать в систему сборки',
        '{{BUILD_VERSION}}': new Date().toISOString().split('T')[0]
    };

    // Выполняем замену
    Object.keys(replacements).forEach(key => {
        content = content.split(key).join(replacements[key]);
    });

    fs.writeFileSync(outputPath, content);
    log(`Собран шаблон: ${outputPath}`, 'green');
}

/**
 * 4. Компиляция стилей (симуляция)
 * В реальном проекте здесь был бы вызов sass/less/webpack
 */
function compileStyles() {
    log('Компиляция стилей...', 'yellow');

    const srcPath = path.join(CONFIG.src, 'styles', 'main.scss');
    const outputPath = path.join(CONFIG.dist, 'css', 'main.css');

    // Создаем демо-стиль, если нет
    if (!fs.existsSync(srcPath)) {
        fs.mkdirSync(path.dirname(srcPath), { recursive: true });
        fs.writeFileSync(srcPath, `$primary: #333;\nbody { background: $primary; color: white; }`);
    }

    // Симуляция компиляции (в реальности здесь был бы вызов sass.render)
    const compiledCss = `/* Скомпилированные стили */\nbody {\n  background-color: #333;\n  color: white;\n}\n`;

    fs.writeFileSync(outputPath, compiledCss);
    log(`Скомпилированы стили: ${outputPath}`, 'green');
}

/**
 * 5. Копирование статических ассетов
 */
function copyAssets() {
    log('Копирование статических ассетов...', 'yellow');

    const srcAssets = path.join(CONFIG.src, 'assets');
    const distAssets = path.join(CONFIG.dist, 'assets');

    if (fs.existsSync(srcAssets)) {
        fs.cpSync(srcAssets, distAssets, { recursive: true });
        log('Ассеты скопированы.', 'green');
    } else {
        log('Папка assets не найдена, пропускаем.', 'blue');
    }
}

/**
 * Главная функция сборки
 */
async function runBuild() {
    const startTime = Date.now();
    log('Запуск системы сборки...', 'blue');

    try {
        setupPublicDirectory();
        generateParserFiles();
        processTemplates();
        compileStyles();
        copyAssets();

        const duration = ((Date.now() - startTime) / 1000).toFixed(2);
        log(`Сборка завершена успешно за ${duration} сек.`, 'green');
        log(`Выходные файлы находятся в: ${CONFIG.dist}`, 'blue');
    } catch (error) {
        log(`Ошибка сборки: ${error.message}`, 'red');
        process.exit(1);
    }
}

// Запуск
runBuild();
```

### Как это работает

1.  **Инициализация (`setupPublicDirectory`)**:
    *   Скрипт удаляет старую папку `public` (чтобы избежать мусора от предыдущих сборок).
    *   Создает новую структуру с подкаталогами `css`, `js`, `assets`, `generated`.

2.  **Генерация парсеров (`generateParserFiles`)**:
    *   Читает JSON-файл спецификации (`parser-spec.json`).
    *   Динамически создает класс JavaScript на основе данных из JSON.
    *   Сохраняет результат в `public/generated/parser.js`.

3.  **Обработка шаблонов (`processTemplates`)**:
    *   Находит файл `.tpl`.
    *   Заменяет маркеры (например, `{{TITLE}}`) на актуальные данные (дата, заголовки).
    *   Сохраняет готовый `index.html` в корень `public`.

4.  **Компиляция стилей (`compileStyles`)**:
    *   Симулирует процесс компиляции SCSS в CSS.
    *   В реальном проекте вы бы подключили библиотеку `sass` или `less` здесь.

5.  **Копирование ассетов (`copyAssets`)**:
    *   Переносит изображения, шрифты и другие статические файлы из `src/assets` в `public/assets`.

