    // MPI_Sendrecv(ctx.d_grid, ..., ctx.d_grid + offset, ...);
    // cudaMemcpy(ctx.d_haloTop, ctx.d_grid + offset, ...);

    // Для демо-целей просто копируем гало из глобальной памяти, 
    // если бы мы работали с одной большой сеткой на одном GPU.
    // В реальном коде здесь будет вызов MPI_Isend/Irecv.
}

// Основной цикл симуляции
void runSimulation(int numGPUs, int width, int height, int iterations) {
    std::vector<GPUContext> contexts(numGPUs);
    int localWidth = width / numGPUs;
    int localHeight = height; // Разбиваем только по X для простоты

    // Инициализация контекстов
    for (int i = 0; i < numGPUs; ++i) {
        contexts[i].deviceId = i;
        contexts[i].width = width;
        contexts[i].height = height;
        contexts[i].localWidth = localWidth;
        contexts[i].localHeight = localHeight;
        contexts[i].haloSize = 1;

        CUDA_CHECK(cudaSetDevice(i));

        // Выделение памяти
        size_t size = localWidth * localHeight;
        CUDA_CHECK(cudaMalloc(&contexts[i].d_grid, size));
        CUDA_CHECK(cudaMalloc(&contexts[i].d_nextGrid, size));
        contexts[i].h_grid = new unsigned char[size];

        // Инициализация данных (разбиваем глобальную сетку)
        unsigned char* tempGrid = new unsigned char[width * height];
        initGrid(tempGrid, width, height);

        // Копируем часть сетки на GPU
        // Смещение для текущего GPU
        int offset = i * localWidth;
        CUDA_CHECK(cudaMemcpy(contexts[i].d_grid, 
                              tempGrid + offset, 
                              size, 
                              cudaMemcpyHostToDevice));

        delete[] tempGrid;
    }

    // Запуск итераций
    dim3 blockDim(BLOCK_SIZE, BLOCK_SIZE);
    dim3 gridDim((localWidth + BLOCK_SIZE - 1) / BLOCK_SIZE, 
                 (localHeight + BLOCK_SIZE - 1) / BLOCK_SIZE);

    for (int iter = 0; iter < iterations; ++iter) {
        for (int i = 0; i < numGPUs; ++i) {
            CUDA_CHECK(cudaSetDevice(i));

            // 1. Обновление гало (обмен с соседями)
            updateHalo(contexts[i], numGPUs, i);

            // 2. Запуск ядра
            gameOfLifeKernel<<<gridDim, blockDim>>>(
                contexts[i].d_grid,
                contexts[i].d_nextGrid,
                contexts[i].width,
                contexts[i].height,
                contexts[i].localWidth,
                contexts[i].localHeight,
                contexts[i].haloSize
            );
            CUDA_CHECK(cudaGetLastError());
            CUDA_CHECK(cudaDeviceSynchronize());

            // 3. Смена буферов (Ping-Pong)
            std::swap(contexts[i].d_grid, contexts[i].d_nextGrid);
        }
    }

    // Сбор результатов и тестирование
    bool testPassed = true;
    for (int i = 0; i < numGPUs; ++i) {
        CUDA_CHECK(cudaSetDevice(i));
        size_t size = contexts[i].localWidth * contexts[i].localHeight;
        CUDA_CHECK(cudaMemcpy(contexts[i].h_grid, contexts[i].d_grid, size, cudaMemcpyDeviceToHost));

        // Простая проверка: если все клетки мертвы после 100 итераций (зависит от паттерна)
        // Для Glider он должен двигаться. Проверим наличие живых клеток.
        int aliveCount = 0;
        for (int j = 0; j < size; ++j) {
            if (contexts[i].h_grid[j] == ALIVE) aliveCount++;
        }

        std::cout << "GPU " << i << ": Живых клеток = " << aliveCount << std::endl;

        // Регрессионный тест: сохраняем изображение, если тест "не проходит"
        // Допустим, тест провален, если живых клеток 0 (для Glider это ошибка)
        if (aliveCount == 0) {
            testPassed = false;
            saveGridToImage(contexts[i].h_grid, contexts[i].localWidth, contexts[i].localHeight, 
                            "failure_gpu_" + std::to_string(i) + ".pgm");
        }
    }

    if (testPassed) {
        std::cout << "Регрессионный тест пройден успешно." << std::endl;
    } else {
        std::cout << "Регрессионный тест НЕ пройден. Изображения сохранены." << std::endl;
    }

    // Очистка памяти
    for (int i = 0; i < numGPUs; ++i) {
        CUDA_CHECK(cudaSetDevice(i));
        cudaFree(contexts[i].d_grid);
        cudaFree(contexts[i].d_nextGrid);
        delete[] contexts[i].h_grid;
    }
}

int main() {
    int numGPUs = 0;
    CUDA_CHECK(cudaGetDeviceCount(&numGPUs));

    if (numGPUs == 0) {
        std::cerr << "Нет доступных GPU." << std::endl;
        return -1;
    }

    std::cout << "Доступно GPU: " << numGPUs << std::endl;

    // Параметры симуляции
    int width = 512;
    int height = 512;
    int iterations = 100;

    try {
        runSimulation(numGPUs, width, height, iterations);
    } catch (const std::exception& e) {
        std::cerr << "Ошибка выполнения: " << e.what() << std::endl;
        return -1;
    }

    return 0;
}
```

### Ключевые особенности реализации

1.  **Оптимизация ядра**:
    *   Используется `__shared__` память (`tile`) для кэширования блока клеток. Это критически важно для производительности, так как уменьшает количество обращений к медленной глобальной памяти (DRAM).
    *   Обработка гало (halo) встроена в логику загрузки в shared memory, что позволяет избежать лишних синхронизаций внутри ядра.

2.  **Много-GPU архитектура**:
    *   Сетка разбивается по горизонтали (`localWidth`).
    *   Цикл `for (int i = 0; i < numGPUs; ++i)` в `runSimulation` переключает контекст (`cudaSetDevice`) и запускает ядро на каждом устройстве.
    *   Функция `updateHalo` (заглушка) предназначена для реализации обмена данными между GPU (например, через MPI). В реальном фреймворке MAPS-Multi эта часть будет реализована через специализированные вызовы библиотеки.

3.  **Тестирование и отладка**:
    *   Используется паттерн "Glider" для инициализации. Это известный паттерн, который должен двигаться по сетке.
    *   После завершения симуляции проверяется количество живых клеток. Если результат не соответствует ожиданиям (например, все клетки мертвы, что невозможно для Glider за 100 итераций), запускается функция `saveGridToImage`.
    *   Формат `.pgm` выбран для простоты и совместимости с большинством просмотрщиков изображений.

4.  **Управление памятью**:
    *   Используется буферная схема (Ping-Pong): `d_grid` и `d_nextGrid` меняются местами после каждой итерации, что исключает необходимость копирования данных обратно на хост на каждом шаге.

### Как компилировать и запускать

Для компиляции используйте `nvcc`:

```bash
nvcc -o gol_simulation gol_simulation.cu -arch=sm_60 -std=c++11
```

*Замените `sm_60` на архитектуру вашего GPU (например, `sm_70`, `sm_80`).*

Для запуска с использованием нескольких GPU (если у вас их несколько):
```bash
./gol_simulation
```

### Примечание по поводу MAPS-Multi

Поскольку MAPS-Multi является специфическим фреймворком, в реальном проекте вы замените:
1.  Ручной цикл `cudaSetDevice` на вызовы инициализации фреймворка.
2.  Функцию `updateHalo` на вызовы API фреймворка для межпроцессного обмена (например, `maps_multi_exchange_halo`).
3.  Логику распределения сетки на вызовы `maps_multi_allocate_grid`.

Представленный код является самодостаточным ядром и логикой управления, которые легко адаптируются под конкретный API фреймворка.
